    "keyword": {
      "foreground": "569cd6",
      "fontStyle": "bold"
    },
    "identifier": "dcdcaa",
    "register": "9cdcfe",
    "variable": "dcdcaa",
    "namespace": "86c691",
    "struct": "4ec9b0",
    "equ": "4fcfff",
    "macro": {
      "foreground": "4ec9b0",
      "fontStyle": "bold italic"
    }
  },
  "lightTheme": {
    "comment": "237122",
    "keyword": {
      "foreground": "0070c0",
      "fontStyle": "bold"
    },
    "identifier": "795e26",
